#include <iostream>
#include <string>
using namespace std;

class Fraction {
private:
    int numerator;   // чисельник
    int denominator; // знаменник

public:
    Fraction(int num = 0, int den = 1) : numerator(num), denominator(den) {}

    // 1. Оголошуємо оператор << ДРУГОМ класу
    // Це НЕ метод класу. Ми просто кажемо: "Ось ця зовнішня функція має доступ до мого private!"
    friend ostream& operator<<(ostream& out, const Fraction& frac);

    // 2. Оголошуємо оператор >> ДРУГОМ для читання з клавіатури через cin
    friend istream& operator>>(istream& in, Fraction& frac);
};

// === ГЛОБАЛЬНІ ФУНКЦІЇ ЗОВНІ КЛАСУ ===

// Оператор << виводить дамп нашого класу у переданий потік (out)
ostream& operator<<(ostream& out, const Fraction& frac) {
    // Дякуючи VIP-friend доступу, можемо спокійно читати приватні frac.numerator!
    out << frac.numerator << "/" << frac.denominator;
    // Обов'язково повертати об'єкт потоку назад для ланцюгового виклику (cout << a << b;)
    return out;
}

// Оператор >> завантажує дані З потоку в об'єкт (передача ЗМІНЮВАНОГО посилання, без const!)
istream& operator>>(istream& in, Fraction& frac) {
    char slash; // Фіктивна змінна для зчитування розділового знаку (слеша)
    in >> frac.numerator >> slash >> frac.denominator;
    return in;
}

int main() {
    Fraction f1(3, 4);

    // Магія в дії! Виводить дроби як рідні об'єкти!
    cout << "Мій перший дріб: " << f1 << endl;

    Fraction f2;
    cout << "Введіть дріб у форматі (Число/Число), наприклад 5/8: ";
    cin >> f2; // Працює бездоганно!

    cout << "Ви ввели: " << f2 << endl;
    cout << "Кінець програми." << endl;

    return 0;
}
